class EventEmitter:
    def __init__(self):
        self._listeners = {}
    def on(self, event, callback):
        if event not in self._listeners:
            self._listeners[event] = []
        self._listeners[event].append(callback)
    def off(self, event, callback):
        if event in self._listeners:
            self._listeners[event].remove(callback)
    def emit(self, event, *args, **kwargs):
        for cb in self._listeners.get(event, []):
            cb(*args, **kwargs)

emitter = EventEmitter()
def on_data(msg): print(f'Data received: {msg}')
def on_error(msg): print(f'Error: {msg}')
emitter.on('data', on_data)
emitter.on('error', on_error)
emitter.emit('data', 'hello world')
emitter.emit('error', 'something went wrong')
emitter.off('data', on_data)
emitter.emit('data', 'this should not print')
print('Observer pattern demo complete')

