def binary_search(arr, target):
    """Binary search on a sorted list. Returns index or -1 if not found."""
    left, right = 0, len(arr) - 1
    while left <= right:
        mid = (left + right) // 2
        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            left = mid + 1
        else:
            right = mid - 1
    return -1

# Demo
sorted_list = [2, 5, 8, 12, 16, 23, 38, 56, 72, 91]
for target in [23, 72, 1, 100]:
    idx = binary_search(sorted_list, target)
    if idx >= 0:
        print(f"Found {target} at index {idx}")
    else:
        print(f"{target} not found")

