import os
import shutil
from datetime import datetime

class LogRotator:
    def __init__(self, log_dir='logs', max_size=1024, max_backups=3):
        self.log_dir = log_dir
        self.max_size = max_size
        self.max_backups = max_backups
        os.makedirs(log_dir, exist_ok=True)
        self.log_file = os.path.join(log_dir, 'app.log')
        if not os.path.exists(self.log_file):
            with open(self.log_file, 'w') as f:
                f.write('')

    def write(self, message):
        with open(self.log_file, 'a') as f:
            f.write(f'{datetime.now().isoformat()} {message}\n')
        if os.path.getsize(self.log_file) > self.max_size:
            self.rotate()

    def rotate(self):
        for i in range(self.max_backups - 1, 0, -1):
            src = f'{self.log_file}.{i}'
            dst = f'{self.log_file}.{i + 1}'
            if os.path.exists(src):
                shutil.move(src, dst)
        shutil.copy2(self.log_file, f'{self.log_file}.1')
        with open(self.log_file, 'w') as f:
            f.write('')

    def list_logs(self):
        return sorted(f for f in os.listdir(self.log_dir) if f.startswith('app.log'))

rotator = LogRotator()
for i in range(20):
    rotator.write(f'Log entry {i}: event processed')
print(f'Log files: {rotator.list_logs()}')
print(f'Rotation complete')

