import os
import json
import csv

def process_data(input_path):
    """Auto-detect file type and process data."""
    if not os.path.exists(input_path):
        print(f'File not found: {input_path}')
        return None
    ext = os.path.splitext(input_path)[1].lower()
    if ext == '.json':
        with open(input_path) as f:
            data = json.load(f)
        print(f'Loaded JSON: {type(data).__name__}')
        if isinstance(data, dict):
            print(f'Keys: {list(data.keys())}')
            for k, v in data.items():
                print(f'  {k}: {v}')
        elif isinstance(data, list):
            print(f'Records: {len(data)}')
            for item in data[:5]:
                print(f'  {item}')
        return data
    elif ext == '.csv':
        with open(input_path) as f:
            reader = csv.DictReader(f)
            rows = list(reader)
        print(f'Loaded CSV: {len(rows)} rows')
        if rows:
            print(f'Columns: {list(rows[0].keys())}')
            for row in rows[:5]:
                print(f'  {dict(row)}')
        return rows
    else:
        with open(input_path) as f:
            lines = f.readlines()
        print(f'Loaded text: {len(lines)} lines')
        for line in lines[:10]:
            print(f'  {line.rstrip()}')
        return lines

# Process available data files
for fname in ['data.json', 'data.csv', 'data.txt']:
    if os.path.exists(fname):
        print(f'\n=== Processing {fname} ===')
        result = process_data(fname)
        print(f'Output: {type(result).__name__} with {len(result) if result else 0} items')
        break
else:
    print('No data files found')
print('Data processing complete')

