import tomllib
import json
import os

def parse_toml(filepath):
    """Parse a TOML config file and return dict."""
    with open(filepath, 'rb') as f:
        return tomllib.load(f)

def write_toml(data, filepath):
    """Write a dict to TOML format."""
    lines = []
    for key, value in data.items():
        if isinstance(value, dict):
            lines.append(f'\n[{key}]')
            for k, v in value.items():
                lines.append(f'{k} = {_toml_value(v)}')
        else:
            lines.append(f'{key} = {_toml_value(value)}')
    with open(filepath, 'w') as f:
        f.write('\n'.join(lines) + '\n')

def _toml_value(v):
    if isinstance(v, str): return f'"{v}"'
    if isinstance(v, bool): return 'true' if v else 'false'
    if isinstance(v, (int, float)): return str(v)
    if isinstance(v, list): return '[' + ', '.join(_toml_value(x) for x in v) + ']'
    return f'"{v}"'

# Demo: create, write, and read TOML config
config = {
    'title': 'FORGE Config',
    'version': 1,
    'debug': False,
    'database': {
        'host': 'localhost',
        'port': 5432,
        'name': 'forge_db'
    },
    'logging': {
        'level': 'INFO',
        'file': 'app.log'
    }
}

toml_path = 'config.toml'
write_toml(config, toml_path)
print(f'Written config to {toml_path}')

parsed = parse_toml(toml_path)
print(f'Parsed config: {json.dumps(parsed, indent=2)}')
print(f'Title: {parsed["title"]}')
print(f'DB host: {parsed["database"]["host"]}')
os.remove(toml_path)
print('TOML parser/writer demo complete')
